solution_code:
#include <stdio.h>
#include <unistd.h>
int is_power_of_2(long n) {
    return n > 0 && (n & (n - 1)) == 0;
}
int main(void) {
    long ps1 = getpagesize();
    long ps2 = sysconf(_SC_PAGESIZE);
    printf("getpagesize: %ld\n", ps1);
    printf("sysconf: %ld\n", ps2);
    printf("Match: %s\n", ps1 == ps2 ? "yes" : "no");
    printf("Power of 2: %s\n", is_power_of_2(ps1) ? "yes" : "no");
    printf("Page size >= 4096: %s\n", ps1 >= 4096 ? "yes" : "no");
    return 0;
}

